/// True if `id` is a known agent capability.
pub fn is_known_agent_capability(id: &str) -> bool {
    AGENT_CAPABILITIES.iter().any(|c| c.id == id)
}

/// Look up the metadata for an agent capability.
pub fn get_agent_capability(id: &str) -> Option<&'static CapabilityMeta> {
    AGENT_CAPABILITIES.iter().find(|c| c.id == id)
}

/// Capabilities that have a runtime enforcement gate today.
pub fn enforced_agent_capabilities() -> impl Iterator<Item = &'static str> {
    AGENT_CAPABILITIES
        .iter()
        .filter(|c| c.enforced)
        .map(|c| c.id)
}
